import React, { useEffect, useMemo, useRef, useState } from "react";
import { MapContainer, TileLayer, LayersControl } from "react-leaflet";
import "leaflet/dist/leaflet.css";

// Simple city -> coords fallback so it works with your favorites right away
const CITY_CENTER = {
  "Atlanta, US": [33.749, -84.388],
  "New York, US": [40.7128, -74.006],
  "London, UK": [51.5074, -0.1278],
  "Dubai, AE": [25.2048, 55.2708],
};

export default function Radar({ city = "Atlanta, US" }) {
  // Center map on selected city, fallback to Atlanta
  const center = CITY_CENTER[city] ?? CITY_CENTER["Atlanta, US"];

  // UI state
  const [opacity, setOpacity] = useState(0.8);
  const [basemap, setBasemap] = useState("voyager"); // voyager | dark | light
  const [isLooping, setIsLooping] = useState(false);

  // You can swap these tile URLs later with your backend or paid providers.
  // Basemaps
  const baseTiles = useMemo(() => {
    const common = { maxZoom: 18, detectRetina: true };
    return {
      voyager: {
        url: "https://{s}.basemaps.cartocdn.com/rastertiles/voyager/{z}/{x}/{y}{r}.png",
        ...common,
      },
      dark: {
        url: "https://{s}.basemaps.cartocdn.com/dark_all/{z}/{x}/{y}{r}.png",
        ...common,
      },
      light: {
        url: "https://{s}.basemaps.cartocdn.com/light_all/{z}/{x}/{y}{r}.png",
        ...common,
      },
    };
  }, []);

  // Radar overlay (RainViewer “now” tiles). Works in most dev setups; if CORS blocks it,
  // just point this at your own tile proxy or another provider.
  const radarTileURL = useMemo(() => {
    // "now" frame (static). Later you can rotate frames like:
    // https://tilecache.rainviewer.com/v2/radar/<timestamp>/256/{z}/{x}/{y}/2/1_1.png
    return "https://tilecache.rainviewer.com/v2/radar/now/256/{z}/{x}/{y}/2/1_1.png";
  }, []);

  // Dummy loop timer you can connect to your own frame list
  const loopTimerRef = useRef(null);
  useEffect(() => {
    if (!isLooping) {
      if (loopTimerRef.current) clearInterval(loopTimerRef.current);
      return;
    }
    // Example: every 800ms you would advance to the next frame and update the tile URL.
    loopTimerRef.current = setInterval(() => {
      // Plug your frame index logic here
      // setFrameIndex((i) => (i + 1) % frames.length)
      // setRadarTileURL(frames[i])
    }, 800);

    return () => {
      if (loopTimerRef.current) clearInterval(loopTimerRef.current);
    };
  }, [isLooping]);

  const activeBase = baseTiles[basemap] || baseTiles.voyager;

  return (
    <div className="relative w-full h-[70vh] sm:h-[75vh] rounded-2xl overflow-hidden shadow-lg">
      {/* Map */}
      <MapContainer
        center={center}
        zoom={8}
        minZoom={3}
        maxZoom={18}
        className="w-full h-full"
        zoomControl={false}
        attributionControl={false}
      >
        <LayersControl position="topright">
          {/* Basemap */}
          <LayersControl.BaseLayer checked name="Basemap">
            <TileLayer url={activeBase.url} maxZoom={activeBase.maxZoom} />
          </LayersControl.BaseLayer>

          {/* Radar overlay */}
          <LayersControl.Overlay checked name="Radar">
            <TileLayer
              url={radarTileURL}
              opacity={opacity}
              tileSize={256}
              zIndex={5}
            />
          </LayersControl.Overlay>
        </LayersControl>
      </MapContainer>

      {/* Glass control panel */}
      <div className="absolute top-3 left-3 z-[1000] bg-black/60 backdrop-blur-md text-white rounded-xl p-3 flex flex-col gap-2 border border-white/10">
        <div className="flex items-center justify-between gap-3">
          <span className="text-sm">Opacity</span>
          <input
            type="range"
            min={0.2}
            max={1}
            step={0.05}
            value={opacity}
            onChange={(e) => setOpacity(parseFloat(e.target.value))}
            className="w-32 accent-purple-500"
          />
        </div>

        <div className="flex items-center justify-between gap-2">
          <span className="text-sm">Basemap</span>
          <select
            value={basemap}
            onChange={(e) => setBasemap(e.target.value)}
            className="bg-black/40 border border-white/10 rounded-lg px-2 py-1 text-sm"
          >
            <option value="voyager">Voyager</option>
            <option value="dark">Dark</option>
            <option value="light">Light</option>
          </select>
        </div>

        <button
          onClick={() => setIsLooping((v) => !v)}
          className={`mt-1 px-3 py-1.5 rounded-lg text-sm transition ${
            isLooping
              ? "bg-purple-600 hover:bg-purple-500"
              : "bg-black/40 hover:bg-black/30 border border-white/10"
          }`}
        >
          {isLooping ? "Stop Loop" : "Play Loop"}
        </button>
      </div>

      {/* Minimal attribution */}
      <div className="absolute bottom-2 right-3 z-[1000] text-[10px] text-white/80 bg-black/40 rounded px-2 py-1">
        Map © CARTO · Radar © RainViewer
      </div>
    </div>
  );
}
